// ODE-solving benchmark runner — CE `DSolve` vs SymPy `dsolve`.
//
// Reads benchmarks/audit/dsolve_cases.json (generated by gen_dsolve.py from
// SymPy's `test_ode.py` classes + textbook ODEs). Runs Compute Engine's
// `DSolve` on each case and grades it with a **substitute-back residual
// oracle**; the SymPy column is its precomputed `dsolve` outcome, graded in
// Python by the *mirror* of this oracle (same sample points, same integration
// constants, same tolerance — all read from the JSON `config` block).
//
// The oracle
// ----------
//   • Explicit solution  y(x) = f(x):   substitute f and its derivatives into
//     the ODE residual, evaluate at the shared sample x-points with c_1,c_2,…
//     fixed; PASS iff |residual| ≤ tol·(1+scale) at ≥ minPoints valid points
//     (points where f leaves the real domain are skipped).
//   • Implicit solution  F(x,y) = C:   replace y(x) by an independent symbol Y,
//     form y' = −F_x/F_y, substitute into the ODE residual, and sample (x,Y)
//     pairs (this first-integral identity holds off the solution curve, so no
//     numeric curve-tracing is needed — see REPORT-dsolve.md).
//   • Initial/boundary conditions are additionally checked numerically.
//
// Grade categories (CE)
//   correct   solved and residual passes            ✅
//   wrong     returned a solution, residual fails    ❌
//   unsupported  expected-inert class, stayed inert  ➖   (CORRECT behavior)
//   gap       should have solved, stayed inert       ⭕
//   n/eval    could not obtain enough sample points  ❔
//   error     runtime error                          ⚠️
//
// CE's contract is **inert-rather-than-wrong**: an inert result on a class it
// does not claim is correct, so `unsupported` is scored apart from `gap`.
//
// Run:  npx tsx benchmarks/audit/dsolve.ts   (grades CE from source; SymPy
//       verdicts come from the committed JSON, regenerate with gen_dsolve.py)

import { readFileSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
// Grade CE from SOURCE (not the packed bundle): this harness measures
// correctness, not speed, and `DSolve` lives in
// src/compute-engine/symbolic/differential-equations.ts — no build required.
import { ComputeEngine } from '../../src/compute-engine';
import type { BoxedExpression } from '../../src/compute-engine/global-types';

const __dirname = dirname(fileURLToPath(import.meta.url));

interface Config {
  constants: Record<string, number>;
  explicitPoints: number[];
  implicitPoints: [number, number][];
  tol: number;
  minPoints: number;
}
interface Condition {
  type: 'value' | 'deriv';
  order?: number;
  at: number;
  target: number;
}
interface Case {
  id: string;
  class: string;
  title: string;
  expectInert: boolean;
  ce: { equation: unknown; dependent: string | string[]; independent: string };
  sympy: { status: string; verdict: string; note?: string; sol?: string };
}
type Verdict =
  | 'correct'
  | 'wrong'
  | 'unsupported'
  | 'gap'
  | 'n/eval'
  | 'error';

const payload = JSON.parse(
  readFileSync(join(__dirname, 'dsolve_cases.json'), 'utf8')
) as { config: Config; cases: Case[] };
const CFG = payload.config;
const cases = payload.cases;

const ce = new ComputeEngine();

// --------------------------------------------------------------------------- //
// MathJSON helpers.
// --------------------------------------------------------------------------- //
const isEqual = (n: any): boolean => Array.isArray(n) && n[0] === 'Equal';

/** Max order of any derivative of a dependent in a MathJSON ODE. */
function maxOrder(node: any): number {
  if (!Array.isArray(node)) return 0;
  if (node[0] === 'D') {
    // Flat form D(f, x, x, …) contributes (nops-1); nested adds recursively.
    let order = node.length - 2;
    let inner = node[1];
    while (Array.isArray(inner) && inner[0] === 'D') {
      order += inner.length - 2;
      inner = inner[1];
    }
    return Math.max(order, maxOrder(node[1]));
  }
  return node
    .slice(1)
    .reduce((m: number, c: any) => Math.max(m, maxOrder(c)), 0);
}

function isCondition(eq: any, deps: string[]): boolean {
  const lhs = eq[1];
  if (!Array.isArray(lhs)) return false;
  if (deps.includes(lhs[0]) && lhs[1] !== 'x') return true; // y(x0)
  if (lhs[0] === 'Apply') return true; // Apply(Derivative(y,k), x0)
  if (
    lhs[0] === 'D' &&
    Array.isArray(lhs[1]) &&
    deps.includes(lhs[1][0]) &&
    lhs[1][1] !== 'x'
  )
    return true; // D(y(x0), x)
  return false;
}

const pointVal = (n: any): number =>
  typeof n === 'number' ? n : ce.box(n).N().re;

function parseCondition(eq: any): Condition {
  const lhs = eq[1];
  const target = pointVal(eq[2]);
  if (lhs[0] === 'Apply') {
    const inner = lhs[1]; // ['Derivative','y',k?]
    const order = inner.length > 2 ? Number(inner[2]) : 1;
    return { type: 'deriv', order, at: pointVal(lhs[2]), target };
  }
  if (lhs[0] === 'D') {
    return { type: 'deriv', order: lhs.length - 2, at: pointVal(lhs[1][1]), target };
  }
  return { type: 'value', at: pointVal(lhs[1]), target };
}

/** Split a case equation into its ODE `Equal` nodes and its conditions. */
function splitCase(
  equation: any,
  deps: string[]
): { odes: any[]; conditions: Condition[] } {
  if (equation[0] === 'Equal') return { odes: [equation], conditions: [] };
  const odes: any[] = [];
  const conditions: Condition[] = [];
  for (const item of equation.slice(1)) {
    if (isCondition(item, deps)) conditions.push(parseCondition(item));
    else odes.push(item);
  }
  return { odes, conditions };
}

// --------------------------------------------------------------------------- //
// Substitution: replace every derivative of `dep` (nested and flat spellings)
// and the plain application dep(x) inside an `Equal` ODE, high order first.
// --------------------------------------------------------------------------- //
function substituteDep(
  eq: BoxedExpression,
  dep: string,
  derivs: BoxedExpression[],
  order: number
): BoxedExpression {
  let out = eq;
  const call = [dep, 'x'];
  for (let k = order; k >= 1; k--) {
    let nested: any = call;
    for (let i = 0; i < k; i++) nested = ['D', nested, 'x'];
    out = out.replace({ match: nested, replace: derivs[k] }, { recursive: true }) ?? out;
    out =
      out.replace(
        { match: ['D', call, ...Array(k).fill('x')], replace: derivs[k] },
        { recursive: true }
      ) ?? out;
  }
  out = out.replace({ match: call, replace: derivs[0] }, { recursive: true }) ?? out;
  return out;
}

/** Evaluate a boxed expression at a numeric substitution → real part, or null
 *  if non-finite / non-real. */
/** Replace any `Derivative(Sign|Abs, …)` distributional term with 0. These
 *  arise when CE differentiates `|u|` (→ `Sign(u)`) a second time (→ the
 *  derivative of `Sign`, a Dirac term). It is 0 almost everywhere, so at the
 *  generic sample points used here — never on the measure-zero kink — zeroing
 *  it is exact, and it avoids a spurious `NaN` from the unevaluated symbol. */
function zeroDistributional(json: any): any {
  if (!Array.isArray(json)) return json;
  if (
    json[0] === 'Apply' &&
    Array.isArray(json[1]) &&
    json[1][0] === 'Derivative' &&
    (json[1][1] === 'Sign' || json[1][1] === 'Abs')
  )
    return 0;
  return json.map(zeroDistributional);
}

function evalReal(
  expr: BoxedExpression,
  sub: Record<string, number>
): number | null {
  try {
    // Re-box through `.json` so a `form:'raw'` (unbound) ODE term — whose `Exp`
    // / `Sin` / … carry no operator definition and would keep `.N()` symbolic —
    // is canonicalized and bound before numeric evaluation.
    const r = ce.box(zeroDistributional(expr.subs(sub).json)).N();
    const re = typeof r.re === 'number' ? r.re : NaN;
    const im = typeof r.im === 'number' ? r.im : 0;
    if (!isFinite(re) || !isFinite(im)) return null;
    if (Math.abs(im) > 1e-7) return null;
    return re;
  } catch {
    return null;
  }
}

// --------------------------------------------------------------------------- //
// Grading.
// --------------------------------------------------------------------------- //
function gradeExplicit(
  odes: any[],
  deps: string[],
  sols: Record<string, BoxedExpression>,
  order: number,
  conditions: Condition[]
): Verdict {
  // Pre-substitute every ODE into a residual (op1 − op2) over x + constants.
  const residuals: BoxedExpression[] = [];
  for (const ode of odes) {
    let eq = ce.expr(ode, { form: 'raw' });
    for (const dep of deps) {
      const derivs: BoxedExpression[] = [sols[dep]];
      for (let k = 1; k <= order; k++)
        derivs.push(ce.function('D', [derivs[k - 1], 'x']).evaluate());
      eq = substituteDep(eq, dep, derivs, order);
    }
    residuals.push(eq);
  }
  let ok = 0;
  for (const xv of CFG.explicitPoints) {
    const sub = { ...CFG.constants, x: xv };
    let scale = 1;
    let evaluable = true;
    for (const dep of deps) {
      const fv = evalReal(sols[dep], sub);
      if (fv === null) {
        evaluable = false;
        break;
      }
      scale += Math.abs(fv);
    }
    if (!evaluable) continue;
    let good = true;
    let allEval = true;
    for (const res of residuals) {
      const lv = evalReal(res.op1, sub);
      const rv = evalReal(res.op2, sub);
      if (lv === null || rv === null) {
        allEval = false;
        break;
      }
      if (Math.abs(lv - rv) > CFG.tol * scale) {
        good = false;
        break;
      }
    }
    if (!allEval) continue;
    if (!good) return 'wrong';
    ok++;
  }
  if (ok < CFG.minPoints) return 'n/eval';
  if (!checkExplicitConditions(deps, sols, conditions)) return 'wrong';
  return 'correct';
}

function checkExplicitConditions(
  deps: string[],
  sols: Record<string, BoxedExpression>,
  conditions: Condition[]
): boolean {
  if (conditions.length === 0) return true;
  const f = sols[deps[0]];
  for (const c of conditions) {
    let target: BoxedExpression = f;
    if (c.type === 'deriv') {
      for (let i = 0; i < (c.order ?? 1); i++)
        target = ce.function('D', [target, 'x']).evaluate();
    }
    const v = evalReal(target, { ...CFG.constants, x: c.at });
    if (v === null || Math.abs(v - c.target) > 1e-6) return false;
  }
  return true;
}

function gradeImplicit(
  ode: any,
  dep: string,
  solEq: BoxedExpression,
  conditions: Condition[]
): Verdict {
  const YSYM = '_Y';
  // relation F0(x,Y) = op1 − op2 with y(x) → Y.
  const F = solEq.op1.replace({ match: [dep, 'x'], replace: YSYM }, { recursive: true }) ?? solEq.op1;
  const G = solEq.op2.replace({ match: [dep, 'x'], replace: YSYM }, { recursive: true }) ?? solEq.op2;
  const relation = ce.function('Subtract', [F, G]);
  const F0x = ce.function('D', [relation, 'x']).evaluate();
  const F0Y = ce.function('D', [relation, YSYM]).evaluate();

  // ODE residual with D(y,x) → placeholder YP, y(x) → Y.
  let eq = ce.expr(ode, { form: 'raw' });
  eq = eq.replace({ match: ['D', [dep, 'x'], 'x'], replace: '_YP' }, { recursive: true }) ?? eq;
  eq = eq.replace({ match: [dep, 'x'], replace: YSYM }, { recursive: true }) ?? eq;

  let ok = 0;
  for (const [xv, yv] of CFG.implicitPoints) {
    const base = { ...CFG.constants, x: xv, [YSYM]: yv };
    const fy = evalReal(F0Y, base);
    const fx = evalReal(F0x, base);
    if (fy === null || fx === null || Math.abs(fy) < 1e-9) continue;
    const yp = -fx / fy;
    const sub = { ...base, _YP: yp };
    const lv = evalReal(eq.op1, sub);
    const rv = evalReal(eq.op2, sub);
    if (lv === null || rv === null) continue;
    const scale = 1 + Math.abs(xv) + Math.abs(yv);
    if (Math.abs(lv - rv) > CFG.tol * scale) return 'wrong';
    ok++;
  }
  if (ok < CFG.minPoints) return 'n/eval';
  // Implicit IC: the relation must vanish at (x0, y0).
  for (const c of conditions) {
    if (c.type !== 'value') return 'wrong';
    const v = evalReal(relation, { ...CFG.constants, x: c.at, [YSYM]: c.target });
    if (v === null || Math.abs(v) > 1e-6) return 'wrong';
  }
  return 'correct';
}

// --------------------------------------------------------------------------- //
// Run one CE case.
// --------------------------------------------------------------------------- //
function runCE(c: Case): { v: Verdict; note?: string } {
  const deps = Array.isArray(c.ce.dependent) ? c.ce.dependent : [c.ce.dependent];
  const depArg = Array.isArray(c.ce.dependent)
    ? ['List', ...c.ce.dependent]
    : c.ce.dependent;
  let sol: BoxedExpression;
  try {
    sol = ce.expr(['DSolve', c.ce.equation, depArg, 'x']).evaluate();
  } catch (e: any) {
    return { v: 'error', note: e?.message?.slice(0, 60) };
  }

  // Inert? (DSolve/NDSolve returned unevaluated, or an Error node)
  if (sol.operator !== 'List') {
    return c.expectInert
      ? { v: 'unsupported' }
      : { v: 'gap', note: 'stayed inert' };
  }

  const { odes, conditions } = splitCase(c.ce.equation, deps);
  const order = Math.max(1, ...odes.map(maxOrder));
  const solEqs = sol.ops ?? [];
  if (solEqs.length === 0) return { v: 'n/eval', note: 'empty solution' };

  // Explicit iff every solution equation is `dep(x) === …`.
  const explicit = solEqs.every(
    (e) => e.op1.operator && deps.includes(e.op1.operator) && e.op1.op1?.symbol === 'x'
  );

  try {
    if (explicit) {
      const sols: Record<string, BoxedExpression> = {};
      for (const e of solEqs) sols[e.op1.operator!] = e.op2;
      // A system must have one solution per dependent.
      if (deps.some((d) => !(d in sols)))
        return { v: 'n/eval', note: 'missing component' };
      const v = gradeExplicit(odes, deps, sols, order, conditions);
      return withUnexpected(c, v);
    }
    // Implicit: scalar first-order only.
    if (deps.length !== 1 || order !== 1)
      return { v: 'n/eval', note: 'implicit non-scalar' };
    const v = gradeImplicit(odes[0], deps[0], solEqs[0], conditions);
    return withUnexpected(c, v);
  } catch (e: any) {
    return { v: 'error', note: 'grade: ' + (e?.message ?? '').slice(0, 40) };
  }
}

/** An expected-inert case that CE actually solved correctly is still `correct`
 *  — flag it so the report can note the surprising win. */
function withUnexpected(c: Case, v: Verdict): { v: Verdict; note?: string } {
  if (c.expectInert && v === 'correct')
    return { v: 'correct', note: 'solved (expected inert)' };
  return { v };
}

// --------------------------------------------------------------------------- //
// Grade + report.
// --------------------------------------------------------------------------- //
const rows = cases.map((c) => ({ c, ce: runCE(c) }));

const SYM: Record<string, string> = {
  correct: '✅',
  wrong: '❌',
  unsupported: '➖',
  gap: '⭕',
  'n/eval': '❔',
  error: '⚠️',
  unsolved: '∅',
};
const symSympy = (v: string) => SYM[v] ?? v;

const classes = [...new Set(cases.map((c) => c.class))];
const ceCorrect = (pred: (c: Case) => boolean) =>
  rows.filter((r) => pred(r.c) && r.ce.v === 'correct').length;
const ceCount = (v: Verdict, pred: (c: Case) => boolean) =>
  rows.filter((r) => pred(r.c) && r.ce.v === v).length;
const syCorrect = (pred: (c: Case) => boolean) =>
  cases.filter((c) => pred(c) && c.sympy.verdict === 'correct').length;

const md: string[] = [];
md.push('# ODE-Solving Benchmark — CE `DSolve` vs SymPy `dsolve`', '');
md.push(
  '_CE is graded **from source** (`src/compute-engine`, no build) — this harness ' +
    'measures **correctness, not speed**. SymPy runs `dsolve` (with a per-case ' +
    'timeout — some calls hang) and is graded in `gen_dsolve.py` by the **mirror** ' +
    'of the oracle below (identical sample points, integration-constant values, ' +
    'and tolerance, all read from the JSON `config`). Regenerate the SymPy column ' +
    'and corpus with `./venv/bin/python3 benchmarks/audit/gen_dsolve.py`._',
  ''
);
md.push(
  'Corpus seeded from SymPy’s `test_ode.py` classes and classic textbook ODEs. ' +
    'Each returned solution is graded by a **substitute-back residual oracle** ' +
    '(§ methodology). CE’s contract is **inert-rather-than-wrong**: staying inert ' +
    'on a class it does not claim is *correct* behavior (`➖ unsupported`), scored ' +
    'apart from `⭕ gap` (should have solved but stayed inert).',
  ''
);
md.push(
  '**✅ correct · ❌ wrong · ➖ unsupported (expected inert = OK) · ⭕ gap (inert but solvable) · ❔ not evaluable · ⚠️ error**',
  ''
);

// Summary
md.push('| Class | n | CE ✅ | CE ➖ | CE ⭕ | CE ❌ | SymPy ✅ |', '|---|--:|--:|--:|--:|--:|--:|');
for (const cls of classes) {
  const p = (c: Case) => c.class === cls;
  const n = cases.filter(p).length;
  md.push(
    `| ${cls} | ${n} | ${ceCorrect(p)} | ${ceCount('unsupported', p)} | ` +
      `${ceCount('gap', p)} | ${ceCount('wrong', p)} | ${syCorrect(p)} |`
  );
}
const all = () => true;
md.push(
  `| **all** | **${cases.length}** | **${ceCorrect(all)}** | ` +
    `**${ceCount('unsupported', all)}** | **${ceCount('gap', all)}** | ` +
    `**${ceCount('wrong', all)}** | **${syCorrect(all)}** |`,
  ''
);

// Per-case grid
md.push('## Cases', '');
md.push('| id | class | ODE | CE | SymPy |', '|---|---|---|:-:|:-:|');
for (const { c, ce: v } of rows) {
  const note = v.note ? ` _(${v.note})_` : '';
  md.push(
    `| ${c.id} | ${c.class} | ${c.title.replace(/\|/g, '\\|')} | ` +
      `${SYM[v.v]}${note} | ${symSympy(c.sympy.verdict)} |`
  );
}
md.push('');

// Methodology
md.push('## Oracle methodology', '');
md.push(
  '- **Explicit** `y(x)=f(x)` (also higher-order and systems): the solution and ' +
    `its derivatives (via CE \`D\`) are substituted into the ODE residual, which ` +
    `is evaluated at x ∈ {${CFG.explicitPoints.join(', ')}} with integration ` +
    `constants ${Object.entries(CFG.constants).map(([k, v]) => `${k}=${v}`).join(', ')}. ` +
    `A point where f leaves the real domain is skipped; PASS needs ` +
    `|residual| ≤ ${CFG.tol}·(1+scale) at ≥ ${CFG.minPoints} points (scale = 1 + Σ|component values|, so large ` +
    'exponential magnitudes are handled relatively).',
  '- **Implicit** `F(x,y)=C` (first-order separable / homogeneous / exact): CE ' +
    'returns these unsolved for y. We replace y(x) by an independent symbol Y and ' +
    'use the **first-integral identity** y′ = −F_x/F_y, substituting it into the ' +
    'ODE residual. For a genuine first integral this identity holds for *all* ' +
    '(x,Y) near the curve — not just on it — so we sample (x,Y) pairs directly ' +
    'instead of numerically tracing F(x,y)=C. Points with |F_y| < 1e-9 are skipped.',
  '- **Initial/boundary conditions** are additionally checked: explicit — f (or ' +
    'fᵏ) at x₀ equals the target within 1e-6; implicit — the relation vanishes at ' +
    '(x₀, y₀).',
  '- The **same** oracle parameters grade SymPy in `gen_dsolve.py` (its own ' +
    'solution differentiated/substituted natively); `checkodesol` is a backstop ' +
    'when the numeric route cannot find enough evaluable points.',
  ''
);

// Findings
md.push('## Findings', '');
const gaps = rows.filter((r) => r.ce.v === 'gap');
const wrongs = rows.filter((r) => r.ce.v === 'wrong');
const neval = rows.filter((r) => r.ce.v === 'n/eval');
const errors = rows.filter((r) => r.ce.v === 'error');
const surprises = rows.filter((r) => r.c.expectInert && r.ce.v === 'correct');
md.push(
  `CE solved **${ceCorrect(all)}/${cases.length}** (${ceCount('unsupported', all)} ` +
    `correctly-inert unsupported, ${ceCount('gap', all)} gap, ${ceCount('wrong', all)} wrong, ` +
    `${neval.length} not-evaluable, ${errors.length} error). SymPy solved ` +
    `**${syCorrect(all)}/${cases.length}**.`,
  ''
);
if (wrongs.length) {
  md.push('**Wrong (returned an unsound solution):**', '');
  for (const r of wrongs) md.push(`- \`${r.c.id}\` ${r.c.title} — ${r.ce.note ?? 'residual failed'}`);
  md.push('');
}
if (gaps.length) {
  md.push('**Gaps (CE stayed inert on a class it should handle):**', '');
  for (const r of gaps)
    md.push(
      `- \`${r.c.id}\` (${r.c.class}) ${r.c.title} — SymPy: ${r.c.sympy.verdict}`
    );
  md.push('');
}
if (neval.length) {
  md.push('**Not evaluable (oracle could not grade — needs review):**', '');
  for (const r of neval) md.push(`- \`${r.c.id}\` ${r.c.title} — ${r.ce.note ?? ''}`);
  md.push('');
}
if (surprises.length) {
  md.push('**Surprises (marked expect-inert but CE solved):**', '');
  for (const r of surprises) md.push(`- \`${r.c.id}\` ${r.c.title}`);
  md.push('');
}

md.push(
  '**Engine observations (found while building the oracle):**',
  '',
  "- `DSolve` is sensitive to term *spelling*: `y'' − y' − y = 0` written as a " +
    "nested `Subtract(Subtract(y'', y'), y)` stays inert, whereas the " +
    "equivalent `Add(y'', Negate(y'), Negate(y))` solves. The recognizer keys off " +
    "the operand structure rather than a fully-normalized form. (L2d is authored " +
    "in the accepted `Add`/`Negate` spelling.)",
  "- Differentiating `|u|` twice yields `Derivative(Sign, 1)` (a distributional " +
    "Dirac term) which `.N()` leaves as an unevaluated symbol → `NaN`. It is 0 " +
    "almost everywhere, so the oracle zeroes it at the generic (kink-free) sample " +
    "points to grade the variation-of-parameters case `NH8` (`y'' + y = tan x`). " +
    "CE’s symbolic answer there is correct; only its second derivative is awkward " +
    "to evaluate numerically.",
  ''
);

writeFileSync(join(__dirname, 'REPORT-dsolve.md'), md.join('\n'));

console.error(
  'Wrote benchmarks/audit/REPORT-dsolve.md (%d cases)',
  cases.length
);
console.error(
  'CE       %d correct  %d unsupported  %d gap  %d wrong  %d n/eval  %d error',
  ceCorrect(all),
  ceCount('unsupported', all),
  ceCount('gap', all),
  ceCount('wrong', all),
  neval.length,
  errors.length
);
console.error('SymPy    %d correct', syCorrect(all));
